mapper.insert:
/** UsptProgrmDao.insert */
insert into uspt_progrm
	(
		progrm_id
		, member_id
		, progrm_type_cd
		, progrm_type_input
		, grad_type_cd
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{progrmId}
		, #{memberId}
		, #{progrmTypeCd}
		, #{progrmTypeInput}
		, #{gradTypeCd}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptProgrmDao.update */
update uspt_progrm
set
	progrm_type_cd		= #{progrmTypeCd}
	, progrm_type_input	= #{progrmTypeInput}
	, grad_type_cd		= #{gradTypeCd}
	, updater_id		= #{updaterId}
	, updated_dt		= #{updatedDt}
where
	member_id = #{memberId}
	and progrm_id = #{progrmId}

mapper.delete:
/** UsptProgrmDao.delete */
delete from uspt_progrm
where
	member_id = #{memberId}
	and progrm_id = #{progrmId}
